          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }

        .error-container {
          color: #ef4444;
        }

        .error-container h3 {
          margin: 24px 0 12px;
          font-size: 24px;
        }

        .error-container p {
          margin: 0 0 24px;
          color: #6b7280;
          max-width: 400px;
        }

        .retry-btn {
          padding: 12px 24px;
          background: #667eea;
          color: white;
          border: none;
          border-radius: 12px;
          font-size: 14px;
          font-weight: 500;
          cursor: pointer;
          display: flex;
          align-items: center;
          gap: 8px;
          transition: all 0.2s;
        }

        .retry-btn:hover {
          background: #5a67d8;
          transform: translateY(-2px);
        }

        /* Responsive Design */
        @media (max-width: 1200px) {
          .summary-cards {
            grid-template-columns: repeat(2, 1fr);
          }
